targets.expr:
group by (instance, instance_id, instance_type, slurm_node) (
    (
      node_uname_info{job="node_exporter"}
        * on(slurm_node) group_left(job_id, job_name)
        label_replace(slurm_job_node_info{job_id="$job_id", job="slurm_exporter"}, "slurm_node", "$1", "node_name", "(.*)")


  )
)

sum(
  irate(node_cpu_seconds_total{mode="system", job="node_exporter"}[$__rate_interval])
  * on(slurm_node) group_left(job_id, job_name)
  label_replace(slurm_job_node_info{job_id="$job_id"}, "slurm_node", "$1", "node_name", "(.*)")
) / scalar(
  count(
    count(
      node_cpu_seconds_total
      * on(slurm_node) group_left(job_id, job_name)
      label_replace(slurm_job_node_info{job_id="$job_id"}, "slurm_node", "$1", "node_name", "(.*)")
    ) by (cpu, slurm_node)
  )
)

