(
  (
    sum(
      node_filesystem_size_bytes{device!~"rootfs", job="node_exporter"}
      * on(slurm_node) group_left(job_id, job_name)
      label_replace(slurm_job_node_info{job_id="$job_id"}, "slurm_node", "$1", "node_name", "(.*)")
    ) by (mountpoint)
    - 
    sum(
      node_filesystem_avail_bytes{device!~"rootfs", job="node_exporter"}
      * on(slurm_node) group_left(job_id, job_name)
      label_replace(slurm_job_node_info{job_id="$job_id"}, "slurm_node", "$1", "node_name", "(.*)")
    ) by (mountpoint)
  ) 
  / 
  sum(
    node_filesystem_size_bytes{device!~"rootfs", job="node_exporter"}
    * on(slurm_node) group_left(job_id, job_name)
    label_replace(slurm_job_node_info{job_id="$job_id"}, "slurm_node", "$1", "node_name", "(.*)")
  ) by (mountpoint)
) * 100
